<template><div class="panel"><div class="section-head"><div><h2>操作日志</h2><p>系统写操作的脱敏审计记录。</p></div><el-button @click="load">刷新</el-button></div><el-table :data="rows"><el-table-column prop="operatedAt" label="时间" width="180"/><el-table-column prop="username" label="用户"/><el-table-column prop="method" label="方法" width="80"/><el-table-column prop="path" label="接口"/><el-table-column prop="durationMs" label="耗时(ms)"/><el-table-column label="结果"><template #default="s"><el-tag :type="s.row.success?'success':'danger'">{{s.row.success?'成功':'失败'}}</el-tag></template></el-table-column><el-table-column prop="errorMessage" label="错误" show-overflow-tooltip/></el-table></div></template><script setup>import{onMounted,ref}from'vue';import http from'../api/http';const rows=ref([]);/** 加载操作日志。 */async function load(){rows.value=(await http.get('/system/operation-logs')).data}onMounted(load)</script>
